                    <div class="stat-label">Countries</div>
                </div>
            </div>
        </div>

        <!-- Content Panel 2 - Rough Trade -->
        <div class="content-panel" id="panel-2">
            <div class="left-content">
                <div class="brand-logo">
                    <div class="rough-trade-logo">
                        <div class="brand-name">ROUGH<br>TRADE</div>
                    </div>
                </div>
                <div class="brand-description">
                    Since 1976, Rough Trade's fiercely independent label has stood for excellence and originality in music. A replatform to Saleor allowed them to sustain their exponential, global growth.
                </div>
            </div>
            <div class="right-content">
                <div class="stat-item">
                    <div class="stat-value">240k+</div>
                    <div class="stat-label">Products</div>
                </div>
                <div class="stat-item">
                    <div class="stat-value">340k+</div>
                    <div class="stat-label">Variants</div>
                </div>
                <div class="stat-item">
                    <div class="stat-value">120k+</div>
                    <div class="stat-label">Attributes</div>
                </div>
                <div class="stat-item">
                    <div class="stat-value">3</div>
                    <div class="stat-label">Languages</div>
                </div>
            </div>
        </div>

        <!-- Progress Indicators -->
        <div class="progress-indicators">
            <div class="indicator-line active" data-panel="1"></div>
            <div class="indicator-line" data-panel="2"></div>
            <div class="indicator-line" data-panel="3"></div>
            <div class="indicator-line" data-panel="4"></div>
            <div class="indicator-line" data-panel="5"></div>
        </div>
    </div>

    <script>
        // DOM Elements
        const indicatorLines = document.querySelectorAll('.indicator-line');
        const contentPanels = document.querySelectorAll('.content-panel');

        // Add click event listeners to indicator lines
        indicatorLines.forEach(line => {
            line.addEventListener('click', function() {
                const panelId = this.getAttribute('data-panel');

                // Remove active class from all indicators
                indicatorLines.forEach(indicator => {
                    indicator.classList.remove('active');
                });

                // Add active class to clicked indicator
                this.classList.add('active');

                // Hide all content panels
                contentPanels.forEach(panel => {
                    panel.classList.remove('active');
                });

                // Show the corresponding content panel
                // For demonstration, we only have 2 panels
                if (panelId === '1' || panelId === '2') {
                    const targetPanel = document.getElementById(`panel-${panelId}`);
                    if (targetPanel) {
                        targetPanel.classList.add('active');
                    }
                }

                // Add a subtle animation effect
                const activePanel = document.querySelector('.content-panel.active');
                if (activePanel) {
                    activePanel.style.transition = 'opacity 0.5s ease, transform 0.5s ease';
                    activePanel.style.transform = 'translateY(0)';
                }
            });
        });

        // Auto-play functionality (optional)
        let currentIndex = 1;
        const maxPanels = 2; // Only 2 panels implemented

        setInterval(() => {
            currentIndex = currentIndex >= maxPanels ? 1 : currentIndex + 1;

            // Find and click the corresponding indicator
            const indicator = document.querySelector(`.indicator-line[data-panel="${currentIndex}"]`);
            if (indicator) {
                indicator.click();
            }
        }, 5000); // Switch every 5 seconds
    </script>
</body>
</html>
