        document.addEventListener('DOMContentLoaded', () => {
            const themeBtn = document.getElementById('theme-btn');
            const themeMenu = document.getElementById('theme-menu');
            const body = document.body;
            const options = document.querySelectorAll('.theme-option');

            // Toggle Menu
            themeBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                themeMenu.classList.toggle('visible');
            });

            // Close menu when clicking outside
            document.addEventListener('click', (e) => {
                if (!themeMenu.contains(e.target) && e.target !== themeBtn) {
                    themeMenu.classList.remove('visible');
                }
            });

            // Handle Theme Selection
            options.forEach(option => {
                option.addEventListener('click', () => {
                    const theme = option.getAttribute('data-theme');

                    // Remove active class from all options
                    options.forEach(opt => opt.classList.remove('active'));
                    // Add active class to clicked option
                    option.classList.add('active');

                    // Apply theme
                    if (theme === 'light') {
                        body.setAttribute('data-theme', 'light');
                    } else if (theme === 'dark') {
                        body.removeAttribute('data-theme'); // Or set explicitly to 'dark'
                    } else {
                        // System preference logic could go here
                        // For this demo, default to dark
                        body.removeAttribute('data-theme');
                    }

                    // Close menu after selection
                    themeMenu.classList.remove('visible');
                });
            });

            // Initialize state to match Image 1 (Dark theme, menu open)
            // Just simulating the click to open the menu as shown in the static screenshot for context
