            // I will ensure the functionality works.

            // For the sake of the first screenshot state, I'll set the default to dark and keep menu closed initially 
            // (or you could set themeMenu.classList.add('visible') to match the static image exactly).
            body.removeAttribute('data-theme'); 
        });
    </script>
