        iconBoxes.forEach(box => {
            box.addEventListener('mouseenter', () => {
                iconBoxes.forEach(b => b.classList.remove('active'));
                box.classList.add('active');
                frameworkName.textContent = box.getAttribute('data-name');
            });
        });

        iconsContainer.addEventListener('mouseleave', () => {
            iconBoxes.forEach(b => b.classList.remove('active'));
            frameworkName.textContent = 'any framework';
